const input = $input.first()?.json ?? {};
const body = input.body ?? {};
const clean = (v) => v === null || v === undefined ? '' : String(v).trim();
const category = clean(body.category) || 'ALL';
const season = clean(body.season) || '2026';
return [{ json: { category, season, teams_dir: '/mnt/c/dev/avondale-n8n/Teams', output_dir: '/mnt/c/dev/avondale-n8n/Teams/generated' } }];

const input = $('Resolve Input').first().json ?? {};
const season = input.season;
const teamsDir = input.teams_dir;
const outputDir = input.output_dir;
const category = input.category;

// Map category to DOCX files
const categoryFiles = {
  'ALL': ['MENS SQUADS 2026 Summer.docx', 'LADIES TEAMS 2026 Summer.docx', 'MIXED TEAMS 2026 SUMMER.docx', 'VETS  TEAMS 2026 SUMMER.docx'],
  'Mens': ['MENS SQUADS 2026 Summer.docx'],
  'Ladies': ['LADIES TEAMS 2026 Summer.docx'],
  'Mixed': ['MIXED TEAMS 2026 SUMMER.docx'],
  'Vets': ['VETS  TEAMS 2026 SUMMER.docx']
};

const files = categoryFiles[category] || categoryFiles['ALL'];
const filesJson = JSON.stringify(files);

const script = `/mnt/c/dev/postgres-mcp-venv-linux/bin/python /mnt/c/dev/avondale-n8n/Teams/generate_team_contact_lists.py`;
const env = { TEAM_CONTACTS_SEASON: '${season}' };

return [{ json: { script, env, files: filesJson, category, season, teams_dir: teamsDir, output_dir: outputDir } }];

const input = $('Build Command').first().json ?? {};
const { execSync } = require('child_process');
try {
  const result = execSync(input.script, {
    env: { ...process.env, ...input.env },
    cwd: input.teams_dir,
    encoding: 'utf8',
    timeout: 120000
  });
  return [{ json: { success: true, output: result, category: input.category, season: input.season } }];
} catch (error) {
  return [{ json: { success: false, error: error.message || error.stderr || 'Unknown error', category: input.category, season: input.season } }];
}
